@dataclass
class FileInfo:
    """Information about a single file"""
    path: str
    relative_path: str
    extension: str
    size: int
    hash: str
    last_modified: datetime
    file_type: str = "unknown"  # schema, dto, controller, service, component, etc.


def _get_build_datetime() -> datetime:
    """Get build datetime, respecting CODETRELLIS_BUILD_TIMESTAMP for determinism (B4 Phase 0)."""
    ts = os.environ.get("CODETRELLIS_BUILD_TIMESTAMP")
    if ts:
        try:
            return datetime.fromisoformat(ts)
        except (ValueError, TypeError):
            pass
    return datetime.now()


@dataclass
class ProjectMatrix:
    """Complete project structure"""
    name: str
    root_path: str
    generated_at: datetime = field(default_factory=_get_build_datetime)

    # Counts
    total_files: int = 0
    total_tokens: int = 0

    # Collections
    services: Dict[str, Any] = field(default_factory=dict)
    schemas: List[Dict] = field(default_factory=list)
    dtos: List[Dict] = field(default_factory=list)
    controllers: List[Dict] = field(default_factory=list)
    components: List[Dict] = field(default_factory=list)
    endpoints: List[Dict] = field(default_factory=list)
    grpc_services: List[Dict] = field(default_factory=list)
    enums: List[Dict] = field(default_factory=list)

    # NEW: v2.0 collections for TypeScript interfaces and types
    interfaces: List[Dict] = field(default_factory=list)
    types: List[Dict] = field(default_factory=list)

    # NEW: v2.0 collections for Angular services and stores
    angular_services: List[Dict] = field(default_factory=list)
    stores: List[Dict] = field(default_factory=list)

    # NEW: v5.1 Angular Guards, Pipes, Directives, Forms (dedicated sections)
    angular_guards: List[Dict] = field(default_factory=list)
