    def __init__(self, ignore_patterns: Optional[Set[str]] = None, parallel: bool = False, max_workers: Optional[int] = None):
        self.ignore_patterns = ignore_patterns or self.DEFAULT_IGNORE
        self.parsers = {}  # Will be populated with file parsers
        self._scan_root = ""  # R4: Set during scan() for relative path checks
        self._gitignore_filter: Optional[GitignoreFilter] = None  # Loaded at scan time

        # Per-file parse cache (Angular SourceFileCache pattern):
        # Maps absolute_file_path → content_hash.  When the builder knows
        # which files changed, it sets _changed_files_hint so _parse_file
        # can skip unchanged files entirely.  The full scan() pipeline still
        # walks every file (to catch deletions and cross-file refs), but the
        # expensive per-file parsing is cached for unchanged files.
        self._changed_files_hint: Optional[set] = None  # Set[str] of abs paths

        # v4.1.1: Parallel processing support
        self.parallel = parallel
        self.parallel_config = ParallelConfig(
            max_workers=max_workers,
            use_processes=False  # Use threads for shared state
        ) if parallel else None
        self.parallel_extractor = ParallelExtractor(self.parallel_config) if parallel else None
        self.error_collector = ErrorCollector()

        # Initialize v2.0 extractors
        self.interface_extractor = InterfaceExtractor()
        self.type_extractor = TypeExtractor()
        self.service_extractor = ServiceExtractor()
        self.store_extractor = StoreExtractor()
        self.route_extractor = RouteExtractor()
        self.websocket_extractor = WebSocketExtractor()
        self.http_api_extractor = HttpApiExtractor()

        # Phase 2: Context extractors
        self.jsdoc_extractor = JSDocExtractor()
        self.readme_extractor = ReadmeExtractor()
        self.config_extractor = ConfigExtractor()

        # v3.0: Error and TODO extractors
        self.error_extractor = ErrorExtractor()
        self.todo_extractor = TodoExtractor()

        # v2.1: Progress and Architecture extractors
        self.progress_extractor = ProgressExtractor()
        self.architecture_extractor = ArchitectureExtractor()

        # v3.1: Business Domain extractor
        self.business_domain_extractor = BusinessDomainExtractor()

        # v4.0: Python parser with all extractors
        self.python_parser = EnhancedPythonParser()

        # v4.33: Django/Flask/FastAPI enhanced parsers
        self.django_parser = EnhancedDjangoParser()
        self.flask_parser = EnhancedFlaskParser()
        self.fastapi_parser = EnhancedFastAPIParser()

        # v4.33: Starlette/SQLAlchemy/Celery enhanced parsers
        self.starlette_parser = EnhancedStarletteParser()
        self.sqlalchemy_parser = EnhancedSQLAlchemyParser()
