        # v4.92: Sanic enhanced parser
        self.sanic_parser = EnhancedSanicParser()

        # v4.93: Litestar enhanced parser
        self.litestar_parser = EnhancedLitestarParser()

        # v4.93: Pydantic enhanced parser
        self.pydantic_enhanced_parser = EnhancedPydanticParser()

        # v4.1: Logic extractor for implementation details
        # Addresses: "AI can't see specific code logic"
        self.logic_extractor = LogicExtractor(max_body_lines=50, include_full_bodies=False)

        # Phase A (v4.2): Runbook extractor for operational context
        # Addresses: G-01 (run commands), G-02 (CI/CD), G-03 (env setup)
        self.runbook_extractor = RunbookExtractor()

