        ruby_types = len(matrix.ruby_classes) + len(matrix.ruby_modules) + len(matrix.ruby_structs)
        ruby_funcs = len(matrix.ruby_methods)
        ruby_api = len(matrix.ruby_routes) + len(matrix.ruby_grpc_services) + len(matrix.ruby_graphql_types)
