    def scan_files_only(self, root_path: str, file_paths: list) -> 'ProjectMatrix':
        """Scan only specific files — used for incremental rebuilds.

        Like Angular's SourceFileCache.invalidate(), this processes only the
        changed files instead of walking the entire project tree.  The returned
        matrix contains entities ONLY from the supplied files; the caller is
        responsible for merging them into the cached whole-project matrix.

        Post-scan extractors (logic, runbook, infrastructure, semantics, etc.)
        are skipped because they do their own full-project walk and their
        results are preserved in the cached matrix for unchanged files.

        Args:
            root_path: Absolute path to the project root
            file_paths: List of Path objects (absolute) to re-scan

        Returns:
            ProjectMatrix with entities extracted from only the given files
        """
        root = Path(root_path).resolve()
        self._scan_root = str(root)

        # Load .gitignore rules
        self._gitignore_filter = GitignoreFilter.from_root(root)

        matrix = ProjectMatrix(
            name=root.name,
            root_path=str(root),
        )

        files_scanned = 0
        for file_path in file_paths:
            file_path = Path(file_path)
            if not file_path.exists():
                continue

            file_info = self._process_file(file_path, root)
            if file_info:
                matrix.files[file_info.relative_path] = file_info
                files_scanned += 1
                self._parse_file(file_path, file_info, matrix)

        matrix.total_files = files_scanned

        print(f"[CodeTrellis] Incremental scan: {files_scanned} files re-extracted")
        return matrix
    def _walk_files(self, root: Path):
        """Walk through all files, respecting ignore patterns and .gitignore.
        
        Files are yielded in sorted order to ensure deterministic output
        across runs (B4 Phase 0 — deterministic file traversal).
        """
        root_str = str(root)
        gi = self._gitignore_filter
        for dirpath, dirnames, filenames in os.walk(root):
            # Filter out ignored directories (check dir name AND relative path segments)
            surviving = []
            for d in sorted(dirnames):
                if self._should_ignore(d):
                    continue
                if self._path_contains_ignored_segment(os.path.join(dirpath, d), root_str):
                    continue
                # .gitignore check
                if gi and not gi.is_empty:
                    rel = os.path.relpath(os.path.join(dirpath, d), root_str)
                    if gi.should_ignore(rel, is_dir=True):
                        continue
                surviving.append(d)
            dirnames[:] = surviving

            for filename in sorted(filenames):
                if self._should_ignore(filename):
                    continue
                # .gitignore check for files
                if gi and not gi.is_empty:
                    rel = os.path.relpath(os.path.join(dirpath, filename), root_str)
                    if gi.should_ignore(rel, is_dir=False):
                        continue
                yield Path(dirpath) / filename

    def _path_contains_ignored_segment(self, full_path: str, root_path: str = "") -> bool:
        """
        Phase A (WS-2 / G-04): Check if ANY segment of the path (relative to
        the project root) matches an ignore pattern. Prevents node_modules deep
        inside nested directories from leaking through (e.g., services/foo/node_modules).

        R4 fix: Only check segments WITHIN the project root, not parent directories
        in the absolute path. Previously, scanning repos stored under a 'tests/'
        directory would cause ALL subdirectories to be skipped because 'tests'
        is in the ignore list and appeared in the absolute path prefix.
        """
        # Use relative path from project root to avoid ignoring based on
        # parent directory names outside the project (e.g., /home/user/tests/myproject/)
        effective_root = root_path or getattr(self, '_scan_root', '')
        if effective_root:
            try:
                rel_path = os.path.relpath(full_path, effective_root)
            except ValueError:
                rel_path = full_path
        else:
            rel_path = full_path

        segments = rel_path.replace('\\', '/').split('/')
        for segment in segments:
            if self._should_ignore(segment):
                return True
        return False

    def _derive_source_service(self, file_path: str, root_path: str) -> Optional[str]:
        """
        Phase B (WS-4 / G-09): Derive the source service name from a file's path.

        Given a file path like '/project/services/nexu-shield/src/auth/auth.controller.ts',
        derives the service name 'nexu-shield'.

        Supports patterns:
        - services/<name>/...  → <name>
        - ai/<name>/...        → <name>
        - apps/<name>/...      → <name>
        - packages/<name>/...  → <name>
        - Root-level files     → None (no service attribution)

        Args:
            file_path: Absolute path to the file
            root_path: Absolute path to the project root

        Returns:
            Service name string, or None if the file is not inside a recognized service directory
        """
        try:
            rel_path = str(Path(file_path).relative_to(root_path)).replace('\\', '/')
        except ValueError:
            return None

        # Known service container directories
        service_containers = ['services', 'ai', 'apps', 'packages', 'projects', 'modules']

        parts = rel_path.split('/')
        for i, part in enumerate(parts):
            if part in service_containers and i + 1 < len(parts):
                return parts[i + 1]

        return None

    def _should_ignore(self, name: str) -> bool:
        """Check if file/directory should be ignored"""
        for pattern in self.ignore_patterns:
            if pattern.startswith("*") and pattern.endswith("*"):
                # *contains* pattern (e.g., *cache*)
                if pattern[1:-1] in name:
                    return True
            elif pattern.startswith("*"):
                # Ends with pattern (e.g., *.spec.ts)
                if name.endswith(pattern[1:]):
                    return True
            elif pattern.endswith("*"):
                # Starts with pattern (e.g., *_env for signal_env)
                if name.endswith(pattern[:-1]):
                    return True
            elif name == pattern:
                return True
        return False

    def _process_file(self, file_path: Path, root: Path) -> Optional[FileInfo]:
        """Process a single file and extract basic info"""
        try:
            stat = file_path.stat()
            content = file_path.read_bytes()

            # Determine file type
            file_type = "unknown"
            for pattern, ftype in self.FILE_TYPES.items():
                if file_path.name.endswith(pattern):
                    file_type = ftype
                    break

            return FileInfo(
                path=str(file_path),
                relative_path=str(file_path.relative_to(root)),
                extension=file_path.suffix,
                size=stat.st_size,
                hash=hashlib.md5(content).hexdigest()[:8],
                last_modified=datetime.fromtimestamp(stat.st_mtime),
                file_type=file_type
            )
        except Exception as e:
            print(f"[CodeTrellis] Warning: Could not process {file_path}: {e}")
            return None

    def _parse_file(self, file_path: Path, file_info: FileInfo, matrix: ProjectMatrix):
        """Parse file content and extract structured data"""
        # Skip example/sample/vendor/generated directories for structural extraction
        # to avoid false-positive frameworks (unified FileClassifier — Phase 1).
        if FileClassifier.should_skip_for_detection(file_info.relative_path):
            return

        # This will be implemented by specific parsers
        # For now, we'll use simple pattern matching

        if file_info.file_type == "schema":
            self._parse_schema(file_path, matrix)
            # v4.78: Angular-typed .ts files may also use GSAP/RxJS
            self._parse_gsap(file_path, matrix)
            self._parse_rxjs(file_path, matrix)
            # v4.81: NestJS enhanced (*.schema.ts may be NestJS Mongoose schemas)
            self._parse_nestjs_enhanced(file_path, matrix)
        elif file_info.file_type == "dto":
            self._parse_dto(file_path, matrix)
            # v4.78: Angular-typed .ts files may also use GSAP/RxJS
            self._parse_gsap(file_path, matrix)
            self._parse_rxjs(file_path, matrix)
            # v4.81: NestJS enhanced (*.dto.ts are NestJS DTOs)
            self._parse_nestjs_enhanced(file_path, matrix)
        elif file_info.file_type == "controller":
            self._parse_controller(file_path, matrix)
            # v4.78: Angular-typed .ts files may also use GSAP/RxJS
            self._parse_gsap(file_path, matrix)
            self._parse_rxjs(file_path, matrix)
            # v4.81: NestJS enhanced (*.controller.ts are NestJS controllers)
            self._parse_nestjs_enhanced(file_path, matrix)
        elif file_info.file_type == "component":
            self._parse_component(file_path, matrix)
            # v4.78: Angular-typed .ts files may also use GSAP/RxJS
            self._parse_gsap(file_path, matrix)
            self._parse_rxjs(file_path, matrix)
        elif file_info.file_type == "proto":
            self._parse_proto(file_path, matrix)
        elif file_info.file_type == "model":
            self._parse_model(file_path, matrix)
            # v4.78: Angular-typed .ts files may also use GSAP/RxJS
            self._parse_gsap(file_path, matrix)
            self._parse_rxjs(file_path, matrix)
            # v4.81: NestJS enhanced (*.model.ts may use NestJS patterns)
            self._parse_nestjs_enhanced(file_path, matrix)
        elif file_info.file_type == "store":
            self._parse_store(file_path, matrix)
            # v4.78: Angular-typed .ts files may also use GSAP/RxJS
            self._parse_gsap(file_path, matrix)
            self._parse_rxjs(file_path, matrix)
        elif file_info.file_type == "service":
            self._parse_angular_service(file_path, matrix)
            # v4.78: Angular-typed .ts files may also use GSAP/RxJS
            self._parse_gsap(file_path, matrix)
            self._parse_rxjs(file_path, matrix)
            # v4.81: NestJS enhanced (*.service.ts are NestJS providers/services)
            self._parse_nestjs_enhanced(file_path, matrix)
        elif file_info.file_type == "routes":
            self._parse_routes(file_path, matrix)
        elif file_info.file_type == "guard":
            # v5.1: Dedicated Angular guard extraction
            self._parse_angular_guard(file_path, matrix)
        elif file_info.file_type == "pipe":
            # v5.1: Dedicated Angular pipe extraction
            self._parse_angular_pipe(file_path, matrix)
        elif file_info.file_type == "directive":
            # v5.1: Dedicated Angular directive extraction
            self._parse_angular_directive(file_path, matrix)
        elif file_info.file_type == "python":
            self._parse_python(file_path, matrix)
        elif file_info.file_type == "go":
            self._parse_go(file_path, matrix)
            # v5.2: Go framework-level parsers (supplementary, run after base Go parser)
            self._parse_gin(file_path, matrix)
            self._parse_echo(file_path, matrix)
            self._parse_fiber(file_path, matrix)
            self._parse_chi(file_path, matrix)
            self._parse_grpc_go(file_path, matrix)
            self._parse_gorm(file_path, matrix)
            self._parse_sqlx(file_path, matrix)
            self._parse_cobra(file_path, matrix)
        elif file_info.file_type == "java":
            self._parse_java(file_path, matrix)
            # v4.94: Java framework-level parsers (supplementary, run after base Java parser)
            self._parse_spring_boot(file_path, matrix)
            self._parse_spring_framework(file_path, matrix)
            self._parse_quarkus(file_path, matrix)
            self._parse_micronaut(file_path, matrix)
            self._parse_jakarta_ee(file_path, matrix)
            # v4.95: Java ecosystem framework parsers
            self._parse_vertx(file_path, matrix)
            self._parse_hibernate(file_path, matrix)
            self._parse_mybatis(file_path, matrix)
            self._parse_apache_camel(file_path, matrix)
            self._parse_akka(file_path, matrix)
