    def _parse_go(self, file_path: Path, matrix: ProjectMatrix):
        """
        Parse Go file using EnhancedGoParser.
        v4.5 (G-17): Full Go language support with structs, interfaces, functions,
        methods, const blocks, HTTP routes, and gRPC services.
        """
        try:
            content = file_path.read_text()
            if not content.strip():
                return

            # Skip test files
            if file_path.name.endswith('_test.go'):
                return

            # Parse with enhanced Go parser
            result = self.go_parser.parse(content, str(file_path))

            # Track package names
            if result.package_name and result.package_name not in matrix.go_packages:
                matrix.go_packages.append(result.package_name)

            # Core Types: Structs
            for struct in result.structs:
                matrix.go_structs.append({
                    "name": struct.name,
                    "file": str(file_path),
                    "fields": [{"name": f.name, "type": f.type, "tag": f.tag, "embedded": f.is_embedded} for f in struct.fields],
                    "embedded_types": struct.embedded_types,
                    "is_exported": struct.is_exported,
                })

            # Core Types: Interfaces
            for iface in result.interfaces:
                matrix.go_interfaces.append({
                    "name": iface.name,
                    "file": str(file_path),
                    "methods": iface.methods,
                    "embedded_interfaces": iface.embedded_interfaces,
                    "is_exported": iface.is_exported,
                })

            # Core Types: Type aliases
            for alias in result.type_aliases:
                matrix.go_type_aliases.append({
                    "name": alias.name,
                    "file": str(file_path),
                    "underlying_type": alias.underlying_type,
                    "is_exported": alias.is_exported,
                })

            # Functions
            for func in result.functions:
                matrix.go_functions.append({
                    "name": func.name,
                    "file": str(file_path),
                    "params": [{"name": p.name, "type": p.type} for p in func.parameters],
                    "return_types": func.return_types,
                    "is_exported": func.is_exported,
                    "is_init": func.is_init,
                    "is_main": func.is_main,
                })

            # Methods (functions with receivers)
            for method in result.methods:
                matrix.go_methods.append({
                    "name": method.name,
                    "file": str(file_path),
                    "receiver_type": method.receiver_type,
                    "is_pointer_receiver": method.is_pointer_receiver,
                    "params": [{"name": p.name, "type": p.type} for p in method.parameters],
                    "return_types": method.return_types,
                    "is_exported": method.is_exported,
                })

            # Const blocks (Go enum equivalents)
            for block in result.const_blocks:
                matrix.go_const_blocks.append({
                    "type_name": block.type_name,
                    "file": str(file_path),
                    "values": [{"name": v.name, "value": v.value} for v in block.values],
                    "uses_iota": block.uses_iota,
                })

            # API routes
            for route in result.routes:
                matrix.go_routes.append({
                    "method": route.method,
                    "path": route.path,
                    "handler": route.handler,
                    "framework": route.framework,
                    "file": str(file_path),
                })

            # gRPC services
            for svc in result.grpc_services:
                matrix.go_grpc_services.append({
                    "name": svc.name,
                    "server_interface": svc.server_interface,
                    "file": str(file_path),
                })

        except Exception as e:
            # Silently skip files that can't be parsed (binary, encoding issues, etc.)
            pass

    def _parse_gin(self, file_path: Path, matrix: ProjectMatrix):
        """Parse Gin framework patterns from Go file. v5.2."""
        try:
            content = file_path.read_text()
            if not content.strip():
                return
            result = self.gin_parser.parse(content, str(file_path))
            if not result.detected_frameworks:
                return
            for fw in result.detected_frameworks:
                if fw not in matrix.go_gin_detected_frameworks:
                    matrix.go_gin_detected_frameworks.append(fw)
            for r in result.routes:
                matrix.go_gin_routes.append(r if isinstance(r, dict) else vars(r))
            for g in result.route_groups:
                matrix.go_gin_route_groups.append(g if isinstance(g, dict) else vars(g))
            for m in result.middleware:
                matrix.go_gin_middleware.append(m if isinstance(m, dict) else vars(m))
            for b in result.bindings:
                matrix.go_gin_bindings.append(b if isinstance(b, dict) else vars(b))
            for r in result.renders:
                matrix.go_gin_renders.append(r if isinstance(r, dict) else vars(r))
            for c in result.engine_configs:
                matrix.go_gin_engine_configs.append(c if isinstance(c, dict) else vars(c))
        except Exception:
            pass

