    def _parse_java(self, file_path: Path, matrix: ProjectMatrix):
        """
        Parse Java file using EnhancedJavaParser.
        v4.12: Full Java language support with classes, interfaces, records,
        enums, annotations, methods, constructors, Spring/JAX-RS/Quarkus/Micronaut
        endpoints, JPA entities, gRPC services, and message listeners.
        """
        try:
            content = file_path.read_text()
            if not content.strip():
                return

            # Skip test files
            fname = file_path.name
            if fname.endswith('Test.java') or fname.endswith('Tests.java') or \
               fname.endswith('IT.java') or fname.startswith('Test'):
                return

            # Parse with enhanced Java parser
            result = self.java_parser.parse(content, str(file_path))

            # Track package names
            if result.package_name and result.package_name not in matrix.java_packages:
                matrix.java_packages.append(result.package_name)

            # Track detected frameworks (deduplicated at matrix level)
            for fw in result.detected_frameworks:
                if fw not in matrix.java_detected_frameworks:
                    matrix.java_detected_frameworks.append(fw)

            # Core Types: Classes
            for cls in result.classes:
                matrix.java_classes.append({
                    "name": cls.name,
                    "kind": cls.kind,
                    "file": str(file_path),
                    "line": cls.line_number,
                    "fields": [{"name": f.name, "type": f.type, "annotations": f.annotations} for f in cls.fields],
                    "methods": cls.methods,
                    "extends": cls.extends,
                    "implements": cls.implements,
                    "annotations": cls.annotations,
                    "generic_params": [{"name": g.name, "bounds": g.bounds} for g in cls.generic_params] if cls.generic_params else [],
                    "is_exported": cls.is_exported,
                    "is_abstract": cls.is_abstract,
                    "is_sealed": cls.is_sealed,
                    "modifiers": cls.modifiers,
                })

            # Core Types: Interfaces
            for iface in result.interfaces:
                matrix.java_interfaces.append({
                    "name": iface.name,
                    "file": str(file_path),
                    "line": iface.line_number,
                    "methods": iface.methods,
                    "extends": iface.extends,
                    "annotations": iface.annotations,
                    "is_exported": iface.is_exported,
                    "is_functional": iface.is_functional,
                    "is_sealed": iface.is_sealed,
                })

            # Core Types: Records (Java 14+)
            for rec in result.records:
                matrix.java_records.append({
                    "name": rec.name,
                    "file": str(file_path),
                    "line": rec.line_number,
                    "components": [{"name": c.name, "type": c.type} for c in rec.components],
                    "implements": rec.implements,
                    "annotations": rec.annotations,
                    "is_exported": rec.is_exported,
                })

            # Core Types: Enums
            for enum in result.enums:
                matrix.java_enums.append({
                    "name": enum.name,
                    "file": str(file_path),
                    "line": enum.line_number,
                    "constants": [{"name": c.name, "arguments": c.arguments} for c in enum.constants],
                    "fields": [{"name": f['name'], "type": f['type']} for f in enum.fields] if enum.fields else [],
                    "methods": enum.methods,
                    "implements": enum.implements,
                    "annotations": enum.annotations,
                    "is_exported": enum.is_exported,
                })

            # Annotation definitions
            for ann_def in result.annotation_defs:
                matrix.java_annotation_defs.append({
                    "name": ann_def.name,
                    "file": str(file_path),
                    "line": ann_def.line_number,
                    "elements": ann_def.elements,
                    "retention": ann_def.retention,
                    "target": ann_def.target,
                })

            # Methods
            for method in result.methods:
                matrix.java_methods.append({
                    "name": method.name,
                    "file": str(file_path),
                    "line": method.line_number,
                    "return_type": method.return_type,
                    "params": [{"name": p.name, "type": p.type, "annotations": p.annotations} for p in method.parameters],
                    "annotations": method.annotations,
                    "modifiers": method.modifiers,
                    "throws": method.throws,
                    "is_override": method.is_override,
                    "is_exported": method.is_exported,
                })

            # Constructors
            for ctor in result.constructors:
                matrix.java_constructors.append({
                    "name": ctor.class_name,
                    "file": str(file_path),
                    "line": ctor.line_number,
                    "params": [{"name": p.name, "type": p.type, "annotations": p.annotations} for p in ctor.parameters],
                    "annotations": ctor.annotations,
                    "modifiers": ctor.modifiers,
                    "is_exported": ctor.is_exported,
                })

            # API endpoints (Spring, JAX-RS, Quarkus, Micronaut)
            for ep in result.endpoints:
                matrix.java_endpoints.append({
                    "method": ep.method,
                    "path": ep.path,
                    "handler": ep.handler_method,
                    "framework": ep.framework,
                    "file": str(file_path),
                    "line": ep.line_number,
                    "consumes": ep.consumes,
                    "produces": ep.produces,
                    "controller": ep.controller_class,
                })

            # gRPC services
            for svc in result.grpc_services:
                matrix.java_grpc_services.append({
                    "name": svc.name,
                    "base_class": svc.base_class,
                    "file": str(file_path),
                    "line": svc.line_number,
                    "methods": svc.methods,
                })

            # Message listeners (Kafka, RabbitMQ, JMS)
            for listener in result.message_listeners:
                matrix.java_message_listeners.append({
                    "handler": listener.handler_method,
                    "topic": listener.topic_or_queue,
                    "type": listener.type,
                    "file": str(file_path),
                    "line": listener.line_number,
                    "group_id": listener.group_id,
                })

            # JPA entities
            for entity in result.entities:
                matrix.java_entities.append({
                    "name": entity.name,
                    "table_name": entity.table_name,
                    "file": str(file_path),
                    "line": entity.line_number,
                    "columns": [{"name": c.name, "type": c.type, "nullable": c.is_nullable, "unique": c.is_unique} for c in entity.columns],
                    "relationships": [{"type": r.type, "target": r.target_entity, "mapped_by": r.mapped_by} for r in entity.relationships],
                    "annotations": entity.annotations,
                })

            # Spring Data repositories
            for repo in result.repositories:
                matrix.java_repositories.append({
                    "name": repo.name,
                    "entity_type": repo.entity_type,
                    "repo_type": repo.base_interface,
                    "file": str(file_path),
                    "line": repo.line_number,
                    "custom_methods": repo.custom_methods,
                })

            # Annotation usages (aggregated for analysis)
            for ann_usage in result.annotation_usages:
                matrix.java_annotations.append({
                    "name": ann_usage.name,
                    "category": ann_usage.category,
                    "target": ann_usage.target,
                    "file": str(file_path),
                    "line": ann_usage.line_number,
                })

        except Exception:
            # Silently skip files that can't be parsed (binary, encoding issues, etc.)
            pass

    def _parse_spring_boot(self, file_path: Path, matrix: ProjectMatrix):
        """
        Parse Spring Boot patterns from Java file.
        v4.94: Extracts beans, configurations, REST endpoints, properties,
        security configs, data repositories, auto-configurations, actuator endpoints.
        Supports Spring Boot 1.x through 3.x.
        """
        try:
            content = file_path.read_text()
            if not content.strip():
                return
            if not self.spring_boot_parser.is_spring_boot_file(content, str(file_path)):
                return

            result = self.spring_boot_parser.parse(content, str(file_path))

            for fw in result.detected_frameworks:
                if fw not in matrix.spring_boot_detected_frameworks:
                    matrix.spring_boot_detected_frameworks.append(fw)
            if result.spring_boot_version and (not matrix.spring_boot_version or result.spring_boot_version > matrix.spring_boot_version):
                matrix.spring_boot_version = result.spring_boot_version

            for b in result.beans:
                matrix.spring_boot_beans.append(b if isinstance(b, dict) else vars(b))
            for c in result.configurations:
                matrix.spring_boot_configurations.append(c if isinstance(c, dict) else vars(c))
            for e in result.endpoints:
                matrix.spring_boot_endpoints.append(e if isinstance(e, dict) else vars(e))
            for p in result.properties:
                matrix.spring_boot_properties.append(p if isinstance(p, dict) else vars(p))
            for s in result.security_configs:
                matrix.spring_boot_security.append(s if isinstance(s, dict) else vars(s))
            for r in result.data_repos:
                matrix.spring_boot_data_repos.append(r if isinstance(r, dict) else vars(r))
            for a in result.autoconfigs:
                matrix.spring_boot_autoconfigs.append(a if isinstance(a, dict) else vars(a))
            for act in result.actuator_endpoints:
                matrix.spring_boot_actuator.append(act if isinstance(act, dict) else vars(act))
        except Exception:
            pass

