    def _parse_php(self, file_path: Path, matrix: ProjectMatrix):
        """
        Parse PHP file using EnhancedPhpParser.
        v4.24: Full PHP language support with classes, interfaces, traits, enums
        (PHP 8.1+), functions, methods, closures, arrow functions (PHP 7.4+),
        Laravel (controllers, routes, models, migrations, Eloquent, Blade),
        Symfony (attributes, Doctrine), Slim/Lumen/CakePHP/CodeIgniter,
        Eloquent ORM, Doctrine ORM, GraphQL (Lighthouse, webonyx),
        gRPC services, composer.json parsing, PHP 8.0+ attributes,
        DI bindings, event listeners, Artisan commands.
        Supports PHP 5.6 through 8.3+ (typed properties, union types, enums,
        readonly classes, fibers, intersection types, DNF types, typed constants).
        """
        try:
            content = file_path.read_text()
            if not content.strip():
                return

            # Skip test files
            fname = file_path.name
            if fname.startswith('test_') or fname.endswith('Test.php') or fname.endswith('_test.php'):
                return
            # Skip test directories
            try:
                rel_path = str(file_path.relative_to(matrix.root_path))
            except (ValueError, TypeError):
                rel_path = str(file_path)
            if '/tests/' in rel_path or '/test/' in rel_path or rel_path.startswith('tests/') or rel_path.startswith('test/'):
                return

            # Handle composer.json specially (dependency parsing)
            if fname == 'composer.json':
                composer_result = self.php_parser.parse_composer_json(content)
                if composer_result.get('php_version'):
                    matrix.php_version = composer_result['php_version']
                for pkg in composer_result.get('packages', []):
                    matrix.php_packages.append({
                        "name": pkg.name,
                        "version": pkg.version,
                        "is_dev": pkg.is_dev,
                        "file": str(file_path),
                    })
                for pkg in composer_result.get('dev_packages', []):
                    matrix.php_packages.append({
                        "name": pkg.name,
                        "version": pkg.version,
                        "is_dev": True,
                        "file": str(file_path),
                    })
                matrix.php_dependencies = {
                    p.name: p.version
                    for p in (composer_result.get('packages', []) + composer_result.get('dev_packages', []))
                }
                return

            # Skip non-PHP content (Blade templates with mostly HTML)
            if fname.endswith('.blade.php'):
                return

            # Parse with enhanced PHP parser
            result = self.php_parser.parse(content, str(file_path))

            # ── Metadata ────────────────────────────────────────────
            for fw in result.detected_frameworks:
                if fw not in matrix.php_detected_frameworks:
                    matrix.php_detected_frameworks.append(fw)

            for imp in result.use_imports:
                if imp not in matrix.php_imports:
                    matrix.php_imports.append(imp)

            if result.php_version and not matrix.php_version:
                matrix.php_version = result.php_version

            # ── Core Types: Classes ──────────────────────────────────
            for cls in result.classes:
                matrix.php_classes.append({
                    "name": cls.name,
                    "file": str(file_path),
                    "line": cls.line_number,
                    "parent": cls.parent_class,
                    "namespace": cls.namespace,
                    "interfaces": cls.interfaces[:10],
                    "traits": cls.traits[:10],
                    "properties": [{"name": p.name, "type": p.type_hint, "visibility": p.visibility} for p in cls.properties[:20]],
                    "constants": [{"name": c.name, "value": c.value} for c in cls.constants[:10]],
                    "is_abstract": cls.is_abstract,
                    "is_final": cls.is_final,
                    "is_readonly": cls.is_readonly,
                    "doc": cls.doc_comment[:200] if cls.doc_comment else "",
                })

            # ── Core Types: Interfaces ───────────────────────────────
            for iface in result.interfaces:
                matrix.php_interfaces.append({
                    "name": iface.name,
                    "file": str(file_path),
                    "line": iface.line_number,
                    "namespace": iface.namespace,
                    "extends": iface.extends[:10],
                    "constants": [{"name": c.name} for c in iface.constants[:10]],
                    "doc": iface.doc_comment[:200] if iface.doc_comment else "",
                })

            # ── Core Types: Traits ───────────────────────────────────
            for trait in result.traits:
                matrix.php_traits.append({
                    "name": trait.name,
                    "file": str(file_path),
                    "line": trait.line_number,
                    "namespace": trait.namespace,
                    "uses_traits": trait.uses_traits[:10],
                    "properties": [{"name": p.name, "type": p.type_hint} for p in trait.properties[:15]],
                    "doc": trait.doc_comment[:200] if trait.doc_comment else "",
                })

            # ── Core Types: Enums ────────────────────────────────────
            for enum in result.enums:
                matrix.php_enums.append({
                    "name": enum.name,
                    "file": str(file_path),
                    "line": enum.line_number,
                    "namespace": enum.namespace,
                    "backed_type": enum.backed_type,
                    "cases": enum.cases[:30],
                    "implements": enum.implements[:5],
                    "traits": enum.traits[:5],
                    "doc": enum.doc_comment[:200] if enum.doc_comment else "",
                })

            # ── Functions ────────────────────────────────────────────
            for func in result.functions:
                matrix.php_functions.append({
                    "name": func.name,
                    "file": str(file_path),
                    "line": func.line_number,
                    "namespace": func.namespace,
                    "params": [{"name": p.name, "type": p.type_hint, "default": p.default_value} for p in func.parameters[:15]],
                    "return_type": func.return_type,
                    "is_generator": func.is_generator,
                    "doc": func.doc_comment[:200] if func.doc_comment else "",
                })

            # ── Methods ──────────────────────────────────────────────
            for method in result.methods:
                matrix.php_methods.append({
                    "name": method.name,
                    "file": str(file_path),
                    "line": method.line_number,
                    "class_name": method.owner_class,
                    "params": [{"name": p.name, "type": p.type_hint, "default": p.default_value} for p in method.parameters[:15]],
                    "return_type": method.return_type,
                    "visibility": method.visibility,
                    "is_static": method.is_static,
                    "is_abstract": method.is_abstract,
                    "is_constructor": method.is_constructor,
                    "is_magic": method.is_magic,
                    "is_generator": method.is_generator,
                    "doc": method.doc_comment[:200] if method.doc_comment else "",
                })

            # ── API Routes ───────────────────────────────────────────
            for route in result.routes:
                matrix.php_routes.append({
                    "method": route.method,
                    "path": route.path,
                    "handler": route.handler,
                    "name": route.name,
                    "middleware": route.middleware[:5],
                    "framework": route.framework,
                    "file": str(file_path),
                    "line": route.line_number,
                })

            # ── Controllers ──────────────────────────────────────────
            for ctrl in result.controllers:
                matrix.php_controllers.append({
                    "name": ctrl.name,
                    "file": str(file_path),
                    "line": ctrl.line_number,
                    "parent": ctrl.parent_class,
                    "actions": ctrl.actions[:30],
                    "middleware": ctrl.middleware[:10],
                    "framework": ctrl.framework,
                })

            # ── Middleware ────────────────────────────────────────────
            for mw in result.middleware:
                matrix.php_middleware.append({
                    "name": mw.name,
                    "kind": mw.kind,
                    "framework": mw.framework,
                    "file": str(file_path),
                    "line": mw.line_number,
                })

            # ── gRPC Services ────────────────────────────────────────
            for grpc in result.grpc_services:
                matrix.php_grpc_services.append({
                    "name": grpc.name,
                    "methods": grpc.methods[:20],
                    "file": str(file_path),
                    "line": grpc.line_number,
                })

            # ── GraphQL Types ────────────────────────────────────────
            for gql in result.graphql_types:
                matrix.php_graphql_types.append({
                    "name": gql.name,
                    "kind": gql.kind,
                    "fields": gql.fields[:30],
                    "framework": gql.framework,
                    "file": str(file_path),
                    "line": gql.line_number,
                })

            # ── Database Models ──────────────────────────────────────
            for model in result.models:
                matrix.php_models.append({
                    "name": model.name,
                    "file": str(file_path),
                    "line": model.line_number,
                    "table_name": model.table_name,
                    "orm": model.orm,
                    "relationships": [{"name": r.name, "type": r.kind, "related": r.related_model} for r in model.relationships[:20]],
                    "fillable": model.fillable[:20],
                    "hidden": model.hidden[:10],
                    "casts": dict(list(model.casts.items())[:10]),
                    "scopes": model.scopes[:15],
                    "uses_soft_deletes": model.uses_soft_deletes,
                    "uses_uuid": model.uses_uuid,
                })

            # ── Migrations ───────────────────────────────────────────
            for mig in result.migrations:
                matrix.php_migrations.append({
                    "name": mig.name,
                    "file": str(file_path),
                    "line": mig.line_number,
                    "tables": mig.tables[:10],
                    "operations": mig.operations[:20],
                    "framework": mig.framework,
                })

            # ── Repositories ─────────────────────────────────────────
            for repo in result.repositories:
                matrix.php_repositories.append({
                    "name": repo.name,
                    "entity": repo.entity,
                    "methods": repo.methods[:20],
                    "orm": repo.orm,
                    "file": str(file_path),
                    "line": repo.line_number,
                })

            # ── Attributes (PHP 8.0+) ────────────────────────────────
            for attr in result.attributes:
                matrix.php_attributes.append({
                    "name": attr.name,
                    "target": attr.target,
                    "arguments": attr.arguments[:5],
                    "file": str(file_path),
                    "line": attr.line_number,
                })

            # ── DI Bindings ──────────────────────────────────────────
            for binding in result.di_bindings:
                matrix.php_di_bindings.append({
                    "abstract": binding.abstract,
                    "concrete": binding.concrete,
                    "kind": binding.kind,
                    "framework": binding.framework,
                    "file": str(file_path),
                    "line": binding.line_number,
                })

            # ── Event Listeners ──────────────────────────────────────
            for listener in result.event_listeners:
                matrix.php_event_listeners.append({
                    "event": listener.event,
                    "listener": listener.listener,
                    "kind": listener.kind,
                    "file": str(file_path),
                    "line": listener.line_number,
                })

            # ── Artisan Commands ─────────────────────────────────────
            for cmd in result.commands:
                matrix.php_commands.append({
                    **cmd,
                    "file": str(file_path),
                })

            # ── Service Providers ────────────────────────────────────
            for sp in result.service_providers:
                matrix.php_service_providers.append({
                    **sp,
                    "file": str(file_path),
                })

        except Exception as e:
            import logging
            logging.getLogger('codetrellis').debug(f"PHP parse failed for {file_path}: {e}")

    def _parse_laravel(self, file_path: Path, matrix: ProjectMatrix):
        """Parse Laravel framework patterns from PHP file. v5.3."""
        try:
            content = file_path.read_text()
            if not content.strip():
                return
            result = self.laravel_parser.parse(content, str(file_path))
            if not result.detected_frameworks:
                return
            for fw in result.detected_frameworks:
                if fw not in matrix.laravel_detected_frameworks:
                    matrix.laravel_detected_frameworks.append(fw)
            if result.laravel_version and not matrix.laravel_version:
                matrix.laravel_version = result.laravel_version
            for r in result.routes:
                matrix.laravel_routes.append(r if isinstance(r, dict) else vars(r))
            for c in result.controllers:
                matrix.laravel_controllers.append(c if isinstance(c, dict) else vars(c))
            for m in result.models:
                matrix.laravel_models.append(m if isinstance(m, dict) else vars(m))
            for mg in result.migrations:
                matrix.laravel_migrations.append(mg if isinstance(mg, dict) else vars(mg))
            for mw in result.middleware:
                matrix.laravel_middleware.append(mw if isinstance(mw, dict) else vars(mw))
            for sp in result.service_providers:
                matrix.laravel_service_providers.append(sp if isinstance(sp, dict) else vars(sp))
            for j in result.jobs:
                matrix.laravel_jobs.append(j if isinstance(j, dict) else vars(j))
            for e in result.events:
                matrix.laravel_events.append(e if isinstance(e, dict) else vars(e))
            for n in result.notifications:
                matrix.laravel_notifications.append(n if isinstance(n, dict) else vars(n))
            for ml in result.mail:
                matrix.laravel_mail.append(ml if isinstance(ml, dict) else vars(ml))
            for p in result.policies:
                matrix.laravel_policies.append(p if isinstance(p, dict) else vars(p))
            for cmd in result.commands:
                matrix.laravel_commands.append(cmd if isinstance(cmd, dict) else vars(cmd))
            for o in result.observers:
                matrix.laravel_observers.append(o if isinstance(o, dict) else vars(o))
            for fr in result.form_requests:
                matrix.laravel_form_requests.append(fr if isinstance(fr, dict) else vars(fr))
            for res in result.resources:
                matrix.laravel_resources.append(res if isinstance(res, dict) else vars(res))
            for b in result.blade_components:
                matrix.laravel_blade_components.append(b if isinstance(b, dict) else vars(b))
            for cfg in result.configs:
                matrix.laravel_configs.append(cfg if isinstance(cfg, dict) else vars(cfg))
        except Exception:
            pass

