    def _parse_bootstrap(self, file_path: Path, matrix: ProjectMatrix):
        """
        Parse Bootstrap file using EnhancedBootstrapParser.
        v4.40: Bootstrap framework-level support. Runs on JS/TS/HTML/CSS/SCSS files
        where Bootstrap is detected. Extracts components (50+ across navbar, modal,
        card, button, form, table, accordion, carousel, offcanvas, etc.),
        custom wrapper components (React-Bootstrap, reactstrap, ng-bootstrap),
        grid system (container/row/col, 6 breakpoints, gutters, ordering, nesting),
        theme config (SCSS variable overrides, CSS custom properties, Bootswatch,
        color modes with data-bs-theme), utility classes (spacing, display, flex,
        sizing, colors, borders, shadows, 16 categories), and JS plugins (Modal,
        Tooltip, Popover, Collapse, Carousel, Offcanvas, Toast + events + CDN).
        Supports Bootstrap v3.x (jQuery, panels/wells) through v5.3+ (vanilla JS,
        CSS Grid, RTL, color modes). 20+ ecosystem detection including react-bootstrap,
        reactstrap, @ng-bootstrap, ngx-bootstrap, bootstrap-vue, bootswatch,
        bootstrap-icons, @popperjs/core.
        """
        try:
            content = file_path.read_text()
            if not content.strip():
                return

            # Only parse if file contains Bootstrap code
            if not self.bootstrap_parser.is_bootstrap_file(content, str(file_path)):
                return

            result = self.bootstrap_parser.parse(content, str(file_path))

            # ── Metadata ────────────────────────────────────────────
            for fw in result.detected_frameworks:
                if fw not in matrix.bootstrap_detected_frameworks:
                    matrix.bootstrap_detected_frameworks.append(fw)

            for feat in result.detected_features:
                if feat not in matrix.bootstrap_detected_features:
                    matrix.bootstrap_detected_features.append(feat)

            if result.bootstrap_version:
                version_order = {'': 0, 'v3': 1, 'v4': 2, 'v5': 3, 'v5.3': 4}
                if version_order.get(result.bootstrap_version, 0) > version_order.get(matrix.bootstrap_version, 0):
                    matrix.bootstrap_version = result.bootstrap_version

            # ── Components ───────────────────────────────────────────
            for comp in result.components:
                matrix.bootstrap_components.append({
                    "name": comp.name,
                    "file": str(file_path),
                    "line": comp.line_number,
                    "import_source": comp.import_source or "",
                    "category": comp.category or "",
                    "variant": comp.variant or "",
                    "props_used": comp.props_used[:15],
                    "classes_used": comp.classes_used[:15],
                    "has_responsive": comp.has_responsive,
                    "has_js_init": comp.has_js_init,
                    "sub_components": comp.sub_components[:10],
                })

            # ── Custom Components ────────────────────────────────────
            for cc in result.custom_components:
                matrix.bootstrap_custom_components.append({
                    "name": cc.name,
                    "file": str(file_path),
                    "line": cc.line_number,
                    "base_component": cc.base_component or "",
                    "method": cc.method or "",
                    "has_theme_usage": cc.has_theme_usage,
                    "additional_props": cc.additional_props[:10],
                })

            # ── Grid System ──────────────────────────────────────────
            for grid in result.grids:
                matrix.bootstrap_grids.append({
                    "grid_type": grid.grid_type or "",
                    "file": str(file_path),
                    "line": grid.line_number,
                    "container_type": grid.container_type or "",
                    "columns": grid.columns[:12],
                    "gutters": grid.gutters[:6],
                    "ordering": grid.ordering[:6],
                    "offsets": grid.offsets[:6],
                    "row_cols": grid.row_cols[:6],
                    "breakpoints_used": grid.breakpoints_used[:6],
                    "is_nested": grid.is_nested,
                })

            # ── Breakpoints ──────────────────────────────────────────
            for bp in result.breakpoints:
                matrix.bootstrap_breakpoints.append({
                    "breakpoint": bp.breakpoint or "",
                    "file": str(file_path),
                    "line": bp.line_number,
                    "context": bp.context or "",
                    "classes": bp.classes[:10],
                })

            # ── Themes ───────────────────────────────────────────────
            for theme in result.themes:
                matrix.bootstrap_themes.append({
                    "name": theme.name or "",
                    "file": str(file_path),
                    "line": theme.line_number,
                    "method": theme.method or "",
                    "bootstrap_version": theme.bootstrap_version or "",
                    "has_custom_colors": theme.has_custom_colors,
                    "has_custom_breakpoints": theme.has_custom_breakpoints,
                    "has_custom_spacing": theme.has_custom_spacing,
                    "has_custom_typography": theme.has_custom_typography,
                    "has_dark_mode": theme.has_dark_mode,
                    "has_color_modes": theme.has_color_modes,
                    "variable_count": theme.variable_count,
                })

            # ── Variables ────────────────────────────────────────────
            for var in result.variables:
                matrix.bootstrap_variables.append({
                    "variable_name": var.variable_name or "",
                    "file": str(file_path),
                    "line": var.line_number,
                    "value": var.value or "",
                    "category": var.category or "",
                    "is_custom_property": var.is_custom_property,
                    "is_override": var.is_override,
                })

            # ── Color Modes ──────────────────────────────────────────
            for cm in result.color_modes:
                matrix.bootstrap_color_modes.append({
                    "mode": cm.mode or "",
                    "file": str(file_path),
                    "line": cm.line_number,
                    "method": cm.method or "",
                    "has_toggle": cm.has_toggle,
                })

            # ── Utilities ────────────────────────────────────────────
            for util in result.utilities:
                matrix.bootstrap_utilities.append({
                    "utility_class": util.utility_class or "",
                    "file": str(file_path),
                    "line": util.line_number,
                    "category": util.category or "",
                    "is_responsive": util.is_responsive,
                    "breakpoint": util.breakpoint or "",
                    "usage_count": util.usage_count,
                })

            # ── Utility Summary ──────────────────────────────────────
            for us in result.utility_summary:
                matrix.bootstrap_utility_summary.append({
                    "category": us.category or "",
                    "total_count": us.total_count,
                    "unique_classes": us.unique_classes,
                    "responsive_count": us.responsive_count,
                    "top_classes": us.top_classes[:10],
                })

            # ── Plugins ──────────────────────────────────────────────
            for plugin in result.plugins:
                matrix.bootstrap_plugins.append({
                    "plugin_name": plugin.plugin_name or "",
                    "file": str(file_path),
                    "line": plugin.line_number,
                    "init_method": plugin.init_method or "",
                    "options": plugin.options[:10],
                    "events_bound": plugin.events_bound[:10],
                })

            # ── Events ───────────────────────────────────────────────
            for evt in result.events:
                matrix.bootstrap_events.append({
                    "event_name": evt.event_name or "",
                    "file": str(file_path),
                    "line": evt.line_number,
                    "component": evt.component or "",
                    "event_type": evt.event_type or "",
                    "method": evt.method or "",
                })

            # ── CDN Includes ─────────────────────────────────────────
            for cdn in result.cdn_includes:
                matrix.bootstrap_cdn_includes.append({
                    "source": cdn.source or "",
                    "file": str(file_path),
                    "line": cdn.line_number,
                    "version": cdn.version or "",
                    "package_name": cdn.package_name or "",
                    "includes_js": cdn.includes_js,
                    "includes_css": cdn.includes_css,
                    "is_bundle": cdn.is_bundle,
                })

        except Exception as e:
            import logging
            logging.getLogger('codetrellis').debug(f"Bootstrap parse failed for {file_path}: {e}")

    def _parse_radix(self, file_path: Path, matrix: ProjectMatrix):
        """
        Parse Radix UI file using EnhancedRadixParser.
        v4.41: Radix UI framework-level support. Runs on JS/TS/CSS files where
        Radix UI is detected. Extracts components (30+ primitives across
        overlay/forms/layout/content/utility categories), themes components
        (50+ styled components from @radix-ui/themes), low-level primitives
        (Slot, Presence, FocusScope, Portal, DismissableLayer, etc.),
        theme configuration (Theme provider props, nested themes, ThemePanel,
        28 color scales × 12 steps), styling patterns (Stitches, CSS Modules,
        Tailwind, styled-components, vanilla-extract, data-attribute CSS),
        and API composition patterns (controlled/uncontrolled state, asChild
        prop composition, Portal rendering, animation library integration).
        Radix UI components are installed as separate npm packages
        (@radix-ui/react-*), each providing headless, accessible primitives.
        Supports Radix Primitives v0.x-v1.x and Radix Themes v1.x-v4.x.
        30+ ecosystem detection including @stitches/react, framer-motion,
        tailwind-merge, CVA, vanilla-extract, react-spring.
        """
        try:
            content = file_path.read_text()
            if not content.strip():
                return

            # Only parse if file contains Radix UI code
            if not self.radix_parser.is_radix_file(content, str(file_path)):
                return

            result = self.radix_parser.parse(content, str(file_path))

            # ── Metadata ────────────────────────────────────────────
            for fw in result.detected_frameworks:
                if fw not in matrix.radix_detected_frameworks:
                    matrix.radix_detected_frameworks.append(fw)

            for feat in result.detected_features:
                if feat not in matrix.radix_detected_features:
                    matrix.radix_detected_features.append(feat)

            if result.radix_version:
                version_order = {
                    '': 0, 'v0': 1, 'v1': 2,
                    'themes-v1': 3, 'themes-v2': 4,
                    'themes-v3': 5, 'themes-v4': 6,
                }
                if version_order.get(result.radix_version, 0) > version_order.get(matrix.radix_version, 0):
                    matrix.radix_version = result.radix_version

            # ── Components (Primitives) ──────────────────────────────
            for comp in result.components:
                matrix.radix_components.append({
                    "name": comp.name,
                    "file": str(file_path),
                    "line": comp.line_number,
                    "import_source": comp.import_source or "",
                    "category": comp.category or "",
                    "is_primitive": comp.is_primitive,
                    "has_as_child": comp.has_as_child,
                    "sub_components": comp.sub_components[:10],
                    "data_attributes": comp.data_attributes[:10],
                    "is_portal": comp.is_portal,
                    "is_controlled": comp.is_controlled,
                })

            # ── Themes Components ────────────────────────────────────
            for tc in result.themes_components:
                matrix.radix_themes_components.append({
                    "name": tc.name,
                    "file": str(file_path),
                    "line": tc.line_number,
                    "category": tc.category or "",
                    "variant": tc.variant or "",
                    "size": tc.size or "",
                    "color": tc.color or "",
                    "high_contrast": tc.high_contrast,
                    "radius": tc.radius or "",
                    "has_responsive": tc.has_responsive,
                })

            # ── Primitives (low-level) ───────────────────────────────
            for prim in result.primitives:
                matrix.radix_primitives.append({
                    "name": prim.name,
                    "file": str(file_path),
                    "line": prim.line_number,
                    "primitive_type": prim.primitive_type or "",
                    "import_source": prim.import_source or "",
                    "has_as_child": prim.has_as_child,
                    "has_force_mount": prim.has_force_mount,
                })

            # ── Slots ────────────────────────────────────────────────
            for slot in result.slots:
                matrix.radix_slots.append({
                    "name": slot.name,
                    "file": str(file_path),
                    "line": slot.line_number,
                    "usage_type": slot.usage_type or "",
                    "wrapped_element": slot.wrapped_element or "",
                })

            # ── Theme Configs ────────────────────────────────────────
            for tc in result.theme_configs:
                matrix.radix_theme_configs.append({
                    "file": str(file_path),
                    "line": tc.line_number,
                    "appearance": tc.appearance or "",
                    "accent_color": tc.accent_color or "",
                    "gray_color": tc.gray_color or "",
                    "panel_background": tc.panel_background or "",
                    "scaling": tc.scaling or "",
                    "radius": tc.radius or "",
                    "is_nested": tc.is_nested,
                    "has_theme_panel": tc.has_theme_panel,
                })

            # ── Color Scales ─────────────────────────────────────────
            for cs in result.color_scales:
                matrix.radix_color_scales.append({
                    "scale_name": cs.scale_name or "",
                    "file": str(file_path),
                    "line": cs.line_number,
                    "steps_used": cs.steps_used[:12],
                    "is_alpha": cs.is_alpha,
                    "is_dark": cs.is_dark,
                })

            # ── Style Patterns ───────────────────────────────────────
            for sp in result.style_patterns:
                matrix.radix_style_patterns.append({
                    "approach": sp.approach or "",
                    "file": str(file_path),
                    "line": sp.line_number,
                    "pattern": sp.pattern or "",
                    "has_dark_mode": sp.has_dark_mode,
                    "has_animation": sp.has_animation,
                    "has_responsive": sp.has_responsive,
                })

            # ── Data Attributes ──────────────────────────────────────
            for da in result.data_attributes:
                matrix.radix_data_attributes.append({
                    "attribute": da.attribute or "",
                    "file": str(file_path),
                    "line": da.line_number,
                    "values": da.values[:10],
                    "component": da.component or "",
                    "context": da.context or "",
                })

            # ── Compositions ─────────────────────────────────────────
            for comp in result.compositions:
                matrix.radix_compositions.append({
                    "name": comp.name,
                    "file": str(file_path),
                    "line": comp.line_number,
                    "pattern_type": comp.pattern_type or "",
                    "sub_components": comp.sub_components[:10],
                    "has_as_child": comp.has_as_child,
                    "has_forward_ref": comp.has_forward_ref,
                })

            # ── Controlled Patterns ──────────────────────────────────
            for cp in result.controlled_patterns:
                matrix.radix_controlled_patterns.append({
                    "component": cp.component or "",
                    "file": str(file_path),
                    "line": cp.line_number,
                    "is_controlled": cp.is_controlled,
                    "state_prop": cp.state_prop or "",
                    "handler_prop": cp.handler_prop or "",
                    "default_prop": cp.default_prop or "",
                })

            # ── Portal Patterns ──────────────────────────────────────
            for pp in result.portal_patterns:
                matrix.radix_portal_patterns.append({
                    "component": pp.component or "",
                    "file": str(file_path),
                    "line": pp.line_number,
                    "has_container": pp.has_container,
                    "has_force_mount": pp.has_force_mount,
                    "animation_library": pp.animation_library or "",
                })

        except Exception as e:
            import logging
            logging.getLogger('codetrellis').debug(f"Radix UI parse failed for {file_path}: {e}")

    def _parse_styled_components(self, file_path: Path, matrix: ProjectMatrix):
        """
        Parse styled-components file using EnhancedStyledComponentsParser.
        v4.42: Styled Components framework-level support. Runs on JS/TS files where
        styled-components (or compatible CSS-in-JS) is detected. Extracts styled
        components (styled.div``, styled(Component)``), extended components,
        theme system (ThemeProvider, createGlobalStyle, useTheme, withTheme),
        mixin patterns (css`` helpers, keyframes``, polished utilities),
        style patterns (CSS properties, media queries, pseudo-selectors,
        dynamic prop interpolation, CSS variables, nesting),
        and API patterns (ServerStyleSheet SSR, StyleSheetManager config,
        babel/SWC plugins, jest-styled-components testing).
        Supports styled-components v1.x through v6.x, @emotion/styled,
        linaria, goober, @stitches/react. 30+ ecosystem detection.
        """
        try:
            content = file_path.read_text()
            if not content.strip():
                return

            # Only parse if file contains styled-components code
            if not self.sc_parser.is_styled_components_file(content, str(file_path)):
                return

            result = self.sc_parser.parse(content, str(file_path))

            # ── Metadata ────────────────────────────────────────────
            for fw in result.detected_frameworks:
                if fw not in matrix.sc_detected_frameworks:
                    matrix.sc_detected_frameworks.append(fw)

            detected_features = []
            if result.has_theme_provider:
                detected_features.append("theme-provider")
            if result.has_global_styles:
                detected_features.append("global-styles")
            if result.has_ssr:
                detected_features.append("ssr")
            if result.has_dynamic_styling:
                detected_features.append("dynamic-styling")
            if result.has_media_queries:
                detected_features.append("media-queries")
            if result.has_keyframes:
                detected_features.append("keyframes")
            if result.has_css_helpers:
                detected_features.append("css-helpers")
            if result.has_transient_props:
                detected_features.append("transient-props")
            if result.has_polished:
                detected_features.append("polished")
            for feat in detected_features:
                if feat not in matrix.sc_detected_features:
                    matrix.sc_detected_features.append(feat)

            if result.sc_version:
                version_order = {'': 0, 'v1': 1, 'v2': 2, 'v3': 3, 'v4': 4, 'v5': 5, 'v6': 6}
                if version_order.get(result.sc_version, 0) > version_order.get(matrix.sc_version, 0):
                    matrix.sc_version = result.sc_version

            if result.css_in_js_library and not matrix.sc_css_in_js_library:
                matrix.sc_css_in_js_library = result.css_in_js_library

            # ── Components ───────────────────────────────────────────
            for comp in result.components:
                matrix.sc_components.append({
                    "name": comp.name,
                    "file": str(file_path),
                    "line": comp.line_number,
                    "base_element": comp.base_element or "",
                    "base_component": comp.base_component or "",
                    "import_source": comp.import_source or "",
                    "has_attrs": comp.has_attrs,
                    "has_with_config": comp.has_with_config,
                    "has_transient_props": comp.has_transient_props,
                    "has_dynamic_props": comp.has_dynamic_props,
                    "has_theme_usage": comp.has_theme_usage,
                    "has_media_query": comp.has_media_query,
                    "css_properties_count": comp.css_properties_count,
                    "style_syntax": comp.style_syntax or "",
                    "method": comp.method or "",
                })

            # ── Extended Components ──────────────────────────────────
            for ext in result.extended_components:
                matrix.sc_extended_components.append({
                    "name": ext.name,
                    "file": str(file_path),
                    "line": ext.line_number,
                    "parent_component": ext.parent_component or "",
                    "additional_styles": ext.additional_styles,
                    "has_overrides": ext.has_overrides,
                    "has_dynamic_props": ext.has_dynamic_props,
                })

            # ── Theme Providers ──────────────────────────────────────
            for prov in result.providers:
                matrix.sc_providers.append({
                    "name": prov.name,
                    "file": str(file_path),
                    "line": prov.line_number,
                    "theme_variable": prov.theme_variable or "",
                    "has_inline_theme": prov.has_inline_theme,
                    "is_nested": prov.is_nested,
                    "token_categories": prov.token_categories[:10],
                })

            # ── Global Styles ────────────────────────────────────────
            for gs in result.global_styles:
                matrix.sc_global_styles.append({
                    "name": gs.name,
                    "file": str(file_path),
                    "line": gs.line_number,
                    "method": gs.method or "",
                    "has_theme_usage": gs.has_theme_usage,
                    "has_css_reset": gs.has_css_reset,
                    "has_font_face": gs.has_font_face,
                    "has_css_variables": gs.has_css_variables,
                })

            # ── Theme Usages ─────────────────────────────────────────
            for tu in result.theme_usages:
                matrix.sc_theme_usages.append({
                    "file": str(file_path),
                    "line": tu.line_number,
                    "method": tu.method or "",
                    "hook_name": tu.hook_name or "",
                    "theme_paths": tu.theme_paths[:10],
                })

            # ── CSS Helpers ──────────────────────────────────────────
            for ch in result.css_helpers:
                matrix.sc_css_helpers.append({
                    "name": ch.name,
                    "file": str(file_path),
                    "line": ch.line_number,
                    "has_interpolation": ch.has_interpolation,
                    "has_nesting": ch.has_nesting,
                    "css_properties_count": ch.css_properties_count,
                })

            # ── Keyframes ────────────────────────────────────────────
            for kf in result.keyframes:
                matrix.sc_keyframes.append({
                    "name": kf.name,
                    "file": str(file_path),
                    "line": kf.line_number,
                    "steps": kf.steps[:10],
                    "properties_animated": kf.properties_animated[:10],
                })

            # ── Mixins ───────────────────────────────────────────────
            for mx in result.mixins:
                matrix.sc_mixins.append({
                    "name": mx.name,
                    "file": str(file_path),
                    "line": mx.line_number,
                    "mixin_type": mx.mixin_type or "",
                    "has_parameters": mx.has_parameters,
                    "is_polished": mx.is_polished,
                })

            # ── Style Patterns ───────────────────────────────────────
            for sp in result.style_patterns:
                matrix.sc_style_patterns.append({
                    "component": sp.component or "",
                    "file": str(file_path),
                    "line": sp.line_number,
                    "categories": sp.categories[:10],
                    "css_properties_count": sp.css_properties_count,
                    "has_nesting": sp.has_nesting,
                    "nesting_depth": sp.nesting_depth,
                    "has_pseudo_selectors": sp.has_pseudo_selectors,
                    "has_css_variables": sp.has_css_variables,
                    "has_flexbox": sp.has_flexbox,
                    "has_grid": sp.has_grid,
                })

            # ── Dynamic Props ────────────────────────────────────────
            for dp in result.dynamic_props:
                matrix.sc_dynamic_props.append({
                    "component": dp.component or "",
                    "file": str(file_path),
                    "line": dp.line_number,
                    "prop_name": dp.prop_name or "",
                    "pattern": dp.pattern or "",
                    "has_ternary": dp.has_ternary,
                    "has_theme_access": dp.has_theme_access,
                })

            # ── Media Queries ────────────────────────────────────────
            for mq in result.media_queries:
                matrix.sc_media_queries.append({
                    "component": mq.component or "",
                    "file": str(file_path),
                    "line": mq.line_number,
                    "breakpoint": mq.breakpoint or "",
                    "approach": mq.approach or "",
                    "is_mobile_first": mq.is_mobile_first,
                    "has_orientation": mq.has_orientation,
                })

            # ── SSR Patterns ─────────────────────────────────────────
            for ssr in result.ssr_patterns:
                matrix.sc_ssr_patterns.append({
                    "file": str(file_path),
                    "line": ssr.line_number,
                    "method": ssr.method or "",
                    "framework": ssr.framework or "",
                    "has_streaming": ssr.has_streaming,
                    "has_rehydration": ssr.has_rehydration,
                })

            # ── Config Patterns ──────────────────────────────────────
            for cfg in result.config_patterns:
                matrix.sc_config_patterns.append({
                    "file": str(file_path),
                    "line": cfg.line_number,
                    "config_type": cfg.config_type or "",
                    "plugin_name": cfg.plugin_name or "",
                    "has_display_name": cfg.has_display_name,
                    "has_ssr": cfg.has_ssr,
                    "has_minify": cfg.has_minify,
                })

            # ── Test Patterns ────────────────────────────────────────
            for tst in result.test_patterns:
                matrix.sc_test_patterns.append({
                    "file": str(file_path),
                    "line": tst.line_number,
                    "test_library": tst.test_library or "",
                    "has_to_have_style_rule": tst.has_to_have_style_rule,
                    "has_snapshot": tst.has_snapshot,
                    "has_theme_render": tst.has_theme_render,
                })

        except Exception as e:
            import logging
            logging.getLogger('codetrellis').debug(f"Styled Components parse failed for {file_path}: {e}")

    def _parse_emotion(self, file_path: Path, matrix: ProjectMatrix):
        """
        Parse Emotion CSS-in-JS file using EnhancedEmotionParser.
        v4.43: Emotion framework-level support. Runs on JS/TS files where
        Emotion (@emotion/react, @emotion/styled, @emotion/css, or legacy
        emotion) is detected. Extracts css prop usage, styled components,
        css function/template, ClassNames render prop, cx composition,
        keyframes animations, Global component, ThemeProvider, useTheme,
        createCache/CacheProvider, SSR patterns, babel/SWC plugins,
        and @emotion/jest testing patterns.
        Supports @emotion/react v11+, @emotion/styled v11+, @emotion/css v11+,
        emotion-theming v10, and legacy emotion v9. 30+ ecosystem detection.
        """
        try:
            content = file_path.read_text()
            if not content.strip():
                return

            # Only parse if file contains Emotion code
            if not self.em_parser.is_emotion_file(content, str(file_path)):
                return

            result = self.em_parser.parse(content, str(file_path))

            # ── Metadata ────────────────────────────────────────────
            for fw in result.detected_frameworks:
                if fw not in matrix.em_detected_frameworks:
                    matrix.em_detected_frameworks.append(fw)

            for feat in result.detected_features:
                if feat not in matrix.em_detected_features:
                    matrix.em_detected_features.append(feat)

            for pkg in result.emotion_packages:
                if pkg not in matrix.em_packages:
                    matrix.em_packages.append(pkg)

            if result.emotion_version:
                version_order = {'': 0, 'v9': 1, 'v10': 2, 'v11': 3}
                if version_order.get(result.emotion_version, 0) > version_order.get(matrix.em_version, 0):
                    matrix.em_version = result.emotion_version

            # ── Styled Components (@emotion/styled) ──────────────────
            for comp in result.components:
                matrix.em_components.append({
                    "name": comp.name,
                    "file": str(file_path),
                    "line": comp.line_number,
                    "base_element": comp.base_element or "",
                    "base_component": comp.base_component or "",
                    "import_source": comp.import_source or "",
                    "has_should_forward_prop": comp.has_should_forward_prop,
                    "has_dynamic_props": comp.has_dynamic_props,
                    "has_theme_usage": comp.has_theme_usage,
                    "has_media_query": comp.has_media_query,
                    "has_nesting": comp.has_nesting,
                    "has_label": comp.has_label,
                    "css_properties_count": comp.css_properties_count,
                    "style_syntax": comp.style_syntax or "",
                    "method": comp.method or "",
                })

            # ── Extended Components ──────────────────────────────────
            for ext in result.extended_components:
                matrix.em_extended_components.append({
                    "name": ext.name,
                    "file": str(file_path),
                    "line": ext.line_number,
                    "parent_component": ext.parent_component or "",
                    "additional_styles": ext.additional_styles,
                    "has_overrides": ext.has_overrides,
                    "has_dynamic_props": ext.has_dynamic_props,
                })

            # ── Theme Providers ──────────────────────────────────────
            for prov in result.providers:
                matrix.em_providers.append({
                    "name": prov.name,
                    "file": str(file_path),
                    "line": prov.line_number,
                    "theme_variable": prov.theme_variable or "",
                    "has_inline_theme": prov.has_inline_theme,
                    "is_nested": prov.is_nested,
                    "token_categories": prov.token_categories[:10],
                    "import_source": prov.import_source or "",
                })

            # ── Global Styles ────────────────────────────────────────
            for gs in result.global_styles:
                matrix.em_global_styles.append({
                    "name": gs.name,
                    "file": str(file_path),
                    "line": gs.line_number,
                    "method": gs.method or "",
                    "has_theme_usage": gs.has_theme_usage,
                    "has_css_reset": gs.has_css_reset,
                    "has_font_face": gs.has_font_face,
                    "has_css_variables": gs.has_css_variables,
                })

            # ── Theme Usages ─────────────────────────────────────────
            for tu in result.theme_usages:
                matrix.em_theme_usages.append({
                    "file": str(file_path),
                    "line": tu.line_number,
                    "method": tu.method or "",
                    "hook_name": tu.hook_name or "",
                    "theme_paths": tu.theme_paths[:10],
                })

            # ── CSS Props ────────────────────────────────────────────
            for cp in result.css_props:
                matrix.em_css_props.append({
                    "file": str(file_path),
                    "line": cp.line_number,
                    "element": cp.element or "",
                    "syntax": cp.syntax or "",
                    "has_theme_usage": cp.has_theme_usage,
                    "has_dynamic": cp.has_dynamic,
                    "css_properties_count": cp.css_properties_count,
                })

            # ── CSS Functions ────────────────────────────────────────
            for cf in result.css_functions:
                matrix.em_css_functions.append({
                    "name": cf.name,
                    "file": str(file_path),
                    "line": cf.line_number,
                    "syntax": cf.syntax or "",
                    "has_interpolation": cf.has_interpolation,
                    "has_nesting": cf.has_nesting,
                    "css_properties_count": cf.css_properties_count,
                })

            # ── ClassNames ───────────────────────────────────────────
            for cn in result.classnames:
                matrix.em_classnames.append({
                    "file": str(file_path),
                    "line": cn.line_number,
                    "has_cx_call": cn.has_cx_call,
                    "has_dynamic": cn.has_dynamic,
                    "css_count": cn.css_count,
                })

            # ── Style Patterns ───────────────────────────────────────
            for sp in result.style_patterns:
                matrix.em_style_patterns.append({
                    "component": sp.component or "",
                    "file": str(file_path),
                    "line": sp.line_number,
                    "categories": sp.categories[:10],
                    "css_properties_count": sp.css_properties_count,
                    "has_nesting": sp.has_nesting,
                    "nesting_depth": sp.nesting_depth,
                    "has_pseudo_selectors": sp.has_pseudo_selectors,
                    "has_css_variables": sp.has_css_variables,
                    "has_flexbox": sp.has_flexbox,
                    "has_grid": sp.has_grid,
                })

            # ── Dynamic Props ────────────────────────────────────────
            for dp in result.dynamic_props:
                matrix.em_dynamic_props.append({
                    "component": dp.component or "",
                    "file": str(file_path),
                    "line": dp.line_number,
                    "prop_name": dp.prop_name or "",
                    "pattern": dp.pattern or "",
                    "has_ternary": dp.has_ternary,
                    "has_theme_access": dp.has_theme_access,
                })

            # ── Media Queries ────────────────────────────────────────
            for mq in result.media_queries:
                matrix.em_media_queries.append({
                    "component": mq.component or "",
                    "file": str(file_path),
                    "line": mq.line_number,
                    "breakpoint": mq.breakpoint or "",
                    "approach": mq.approach or "",
                    "is_mobile_first": mq.is_mobile_first,
                    "has_orientation": mq.has_orientation,
                })

            # ── Keyframes ────────────────────────────────────────────
            for kf in result.keyframes:
                matrix.em_keyframes.append({
                    "name": kf.name,
                    "file": str(file_path),
                    "line": kf.line_number,
                    "steps": kf.steps[:10],
                    "properties_animated": kf.properties_animated[:10],
                })

            # ── Animation Usages ─────────────────────────────────────
            for au in result.animation_usages:
                matrix.em_animation_usages.append({
                    "name": au.name,
                    "file": str(file_path),
                    "line": au.line_number,
                    "has_composition": au.has_composition,
                    "is_transition": au.is_transition,
                })

            # ── Caches ───────────────────────────────────────────────
            for cache in result.caches:
                matrix.em_caches.append({
                    "name": cache.name,
                    "file": str(file_path),
                    "line": cache.line_number,
                    "cache_key": cache.cache_key or "",
                    "has_nonce": cache.has_nonce,
                    "has_prepend": cache.has_prepend,
                    "has_container": cache.has_container,
                    "has_stylis_plugins": cache.has_stylis_plugins,
                })

            # ── SSR Patterns ─────────────────────────────────────────
            for ssr in result.ssr_patterns:
                matrix.em_ssr_patterns.append({
                    "file": str(file_path),
                    "line": ssr.line_number,
                    "method": ssr.method or "",
                    "framework": ssr.framework or "",
                    "has_streaming": ssr.has_streaming,
                    "has_chunks": ssr.has_chunks,
                })

            # ── Babel/SWC Configs ────────────────────────────────────
            for bc in result.babel_configs:
                matrix.em_babel_configs.append({
                    "file": str(file_path),
                    "line": bc.line_number,
                    "plugin_type": bc.plugin_type or "",
                    "has_auto_label": bc.has_auto_label,
                    "has_source_map": bc.has_source_map,
                    "has_import_source": bc.has_import_source,
                })

            # ── Test Patterns ────────────────────────────────────────
            for tst in result.test_patterns:
                matrix.em_test_patterns.append({
                    "file": str(file_path),
                    "line": tst.line_number,
                    "test_library": tst.test_library or "",
                    "has_to_have_style_rule": tst.has_to_have_style_rule,
                    "has_snapshot_serializer": tst.has_snapshot_serializer,
                    "has_theme_render": tst.has_theme_render,
                })

        except Exception as e:
            import logging
            logging.getLogger('codetrellis').debug(f"Emotion parse failed for {file_path}: {e}")

    def _parse_express(self, file_path: Path, matrix: ProjectMatrix):
        """
        Parse Express.js file using EnhancedExpressParser.
        v4.80: Express.js backend framework support. Runs on JS/TS files where
        Express.js is detected. Extracts routes, routers, params, middleware,
        error handlers, configuration, API patterns, resources, and versioning.
        Supports Express 3.x through 5.x.
        """
        try:
            content = file_path.read_text()
            if not content.strip():
                return

            # Only parse if file contains Express.js code
            if not self.express_parser.is_express_file(content, str(file_path)):
                return

            result = self.express_parser.parse(content, str(file_path))

            # ── Metadata ────────────────────────────────────────────
            for fw in result.detected_frameworks:
                if fw not in matrix.express_detected_frameworks:
                    matrix.express_detected_frameworks.append(fw)

            if result.express_version and (
                not matrix.express_version or result.express_version > matrix.express_version
            ):
                matrix.express_version = result.express_version

            if result.is_typescript:
                matrix.express_is_typescript = True

            # ── Routes ──────────────────────────────────────────────
            for route in result.routes:
                matrix.express_routes.append({
                    "method": route.method,
                    "path": route.path,
                    "handler": route.handler,
                    "file": str(file_path),
                    "line": route.line_number,
                    "is_async": route.is_async,
                    "has_middleware": route.has_middleware,
                    "middleware_count": route.middleware_count,
                    "middleware_names": route.middleware_names[:10],
                    "has_params": route.has_params,
                    "param_names": route.param_names[:10],
                    "is_dynamic": route.is_dynamic,
                    "router_name": route.router_name or "",
                    "response_type": route.response_type or "",
                })

            # ── Routers ─────────────────────────────────────────────
            for router in result.routers:
                matrix.express_routers.append({
                    "name": router.name,
                    "file": str(file_path),
                    "line": router.line_number,
                    "mount_path": router.mount_path or "",
                    "route_count": router.route_count,
                    "has_middleware": router.has_middleware,
                    "middleware_names": router.middleware_names[:10],
                })

            # ── Params ──────────────────────────────────────────────
            for param in result.params:
                matrix.express_params.append({
                    "param_name": param.param_name,
                    "handler": param.handler,
                    "file": str(file_path),
                    "line": param.line_number,
                    "router_name": param.router_name or "",
                })

            # ── Middleware ───────────────────────────────────────────
            for mw in result.middleware:
                matrix.express_middleware.append({
                    "name": mw.name,
                    "file": str(file_path),
                    "line": mw.line_number,
                    "middleware_type": mw.middleware_type or "",
                    "category": mw.category or "",
                    "is_global": mw.is_global,
                    "mount_path": mw.mount_path or "",
                    "source_package": mw.source_package or "",
                })

            # ── Middleware Stack ─────────────────────────────────────
            if result.middleware_stack:
                ms = result.middleware_stack
                matrix.express_middleware_stacks.append({
                    "file": str(file_path),
                    "total_middleware": ms.total_middleware,
                    "global_middleware": ms.global_middleware,
                    "has_cors": ms.has_cors,
                    "has_helmet": ms.has_helmet,
                    "has_compression": ms.has_compression,
                    "has_session": ms.has_session,
                    "has_auth": ms.has_auth,
                    "has_rate_limiting": ms.has_rate_limiting,
                    "has_body_parser": ms.has_body_parser,
                    "has_cookie_parser": ms.has_cookie_parser,
                    "has_morgan": ms.has_morgan,
                    "has_static": ms.has_static,
                })

            # ── Error Handlers ──────────────────────────────────────
            for eh in result.error_handlers:
                matrix.express_error_handlers.append({
                    "name": eh.name,
                    "file": str(file_path),
                    "line": eh.line_number,
                    "handler_type": eh.handler_type or "",
                    "has_logging": eh.has_logging,
                    "is_async": eh.is_async,
                    "sends_json": eh.sends_json,
                })

            # ── Custom Errors ───────────────────────────────────────
            for ce in result.custom_errors:
                matrix.express_custom_errors.append({
                    "name": ce.name,
                    "file": str(file_path),
                    "line": ce.line_number,
                    "extends": ce.extends,
                    "status_code": ce.status_code,
                })

            # ── Settings ────────────────────────────────────────────
            for setting in result.settings:
                matrix.express_settings.append({
                    "name": setting.name,
                    "value": setting.value or "",
                    "file": str(file_path),
                    "line": setting.line_number,
                    "setting_type": setting.setting_type or "",
                    "is_env_based": setting.is_env_based,
                })

            # ── Apps ────────────────────────────────────────────────
            for app in result.apps:
                matrix.express_apps.append({
                    "variable_name": app.variable_name,
                    "file": str(file_path),
                    "line": app.line_number,
                    "is_exported": app.is_exported,
                    "creation_style": app.creation_style or "",
                })

            # ── Servers ─────────────────────────────────────────────
            for srv in result.servers:
                matrix.express_servers.append({
                    "file": str(file_path),
                    "line": srv.line_number,
                    "port": srv.port or "",
                    "host": srv.host or "",
                    "is_https": srv.is_https,
                    "uses_cluster": srv.uses_cluster,
                })

            # ── Resources ───────────────────────────────────────────
            for res in result.resources:
                matrix.express_resources.append({
                    "name": res.name,
                    "base_path": res.base_path or "",
                    "file": str(file_path),
                    "operations": res.operations[:10],
                    "has_list": res.has_list,
                    "has_detail": res.has_detail,
                    "has_create": res.has_create,
                    "has_update": res.has_update,
                    "has_delete": res.has_delete,
                    "has_nested": res.has_nested,
                })

            # ── Response Patterns ───────────────────────────────────
            for rp in result.response_patterns:
                matrix.express_response_patterns.append({
                    "file": str(file_path),
                    "line": rp.line_number,
                    "response_type": rp.response_type or "",
                    "status_code": rp.status_code,
                })

            # ── API Versions ────────────────────────────────────────
            for av in result.api_versions:
                matrix.express_api_versions.append({
                    "version": av.version or "",
                    "prefix": av.prefix or "",
                    "file": str(file_path),
                    "line": av.line_number,
                    "route_count": av.route_count,
                })

        except Exception as e:
            import logging
            logging.getLogger('codetrellis').debug(f"Express.js parse failed for {file_path}: {e}")

    def _parse_nestjs_enhanced(self, file_path: Path, matrix: ProjectMatrix):
        """
        Parse NestJS file using EnhancedNestJSParser (per-file).
        v4.81: NestJS enhanced per-file support. Runs on TS files where
        NestJS decorators are detected. Extracts modules, controllers,
        providers, DI injections, config, Swagger/OpenAPI decorators, DTOs.
        Complements the existing project-level NestJSExtractor.
        Supports NestJS 7.x through 10.x.
        """
        try:
            content = file_path.read_text()
            if not content.strip():
                return

            # Only parse if file contains NestJS code
            if not self.nestjs_enhanced_parser.is_nestjs_file(content, str(file_path)):
                return

            result = self.nestjs_enhanced_parser.parse(content, str(file_path))

            # ── Metadata ────────────────────────────────────────────
            for fw in result.detected_frameworks:
                if fw not in matrix.nestjs_enhanced_detected_frameworks:
                    matrix.nestjs_enhanced_detected_frameworks.append(fw)

            if result.nestjs_version and (
                not matrix.nestjs_enhanced_version or result.nestjs_version > matrix.nestjs_enhanced_version
            ):
                matrix.nestjs_enhanced_version = result.nestjs_version

            if result.has_swagger:
                matrix.nestjs_enhanced_has_swagger = True
            if result.has_validation:
                matrix.nestjs_enhanced_has_validation = True

            # ── Modules ─────────────────────────────────────────────
            for mod in result.modules:
                matrix.nestjs_enhanced_modules.append({
                    "class_name": mod.class_name,
                    "file": str(file_path),
                    "line": mod.line_number,
                    "imports": mod.imports[:20],
                    "providers": mod.providers[:20],
                    "controllers": mod.controllers[:20],
                    "exports": mod.exports[:20],
                    "is_global": mod.is_global,
                    "is_dynamic": mod.is_dynamic,
                })

            # ── Module Providers ─────────────────────────────────────
            for mp in result.module_providers:
                matrix.nestjs_enhanced_module_providers.append({
                    "name": mp.name,
                    "file": str(file_path),
                    "line": mp.line_number,
                    "provide_token": mp.provide_token or "",
                    "use_class": mp.use_class or "",
                    "use_factory": mp.use_factory or "",
                    "is_custom": mp.is_custom,
                })

            # ── Dynamic Modules ──────────────────────────────────────
            for dm in result.dynamic_modules:
                matrix.nestjs_enhanced_dynamic_modules.append({
                    "method_name": dm.method_name,
                    "module_class": dm.module_class or "",
                    "file": str(file_path),
                    "line": dm.line_number,
                    "is_async": dm.is_async,
                    "has_options": dm.has_options,
                })

            # ── Controllers ──────────────────────────────────────────
            for ctrl in result.controllers:
                matrix.nestjs_enhanced_controllers.append({
                    "class_name": ctrl.class_name,
                    "path": ctrl.path or "",
                    "file": str(file_path),
                    "line": ctrl.line_number,
                    "version": ctrl.version or "",
                    "total_endpoints": ctrl.total_endpoints,
                    "has_guards": ctrl.has_guards,
                    "guard_names": ctrl.guard_names[:10],
                    "has_interceptors": ctrl.has_interceptors,
                    "has_pipes": ctrl.has_pipes,
                })

            # ── Param Decorators ─────────────────────────────────────
            for pd in result.param_decorators:
                matrix.nestjs_enhanced_param_decorators.append({
                    "decorator": pd.decorator,
                    "param_name": pd.param_name or "",
                    "file": str(file_path),
                    "line": pd.line_number,
                })

            # ── Injectables ──────────────────────────────────────────
            for inj in result.injectables:
                matrix.nestjs_enhanced_injectables.append({
                    "class_name": inj.class_name,
                    "file": str(file_path),
                    "line": inj.line_number,
                    "scope": inj.scope or "DEFAULT",
                    "injectable_type": inj.injectable_type or "",
                    "implements": inj.implements[:10],
                    "injections": inj.injections[:10],
                })

            # ── Injections ───────────────────────────────────────────
            for ij in result.injections:
                matrix.nestjs_enhanced_injections.append({
                    "class_name": ij.class_name,
                    "param_name": ij.param_name or "",
                    "param_type": ij.param_type or "",
                    "inject_token": ij.inject_token or "",
                    "is_optional": ij.is_optional,
                    "file": str(file_path),
                    "line": ij.line_number,
                })

            # ── Custom Providers ─────────────────────────────────────
            for cp in result.custom_providers:
                matrix.nestjs_enhanced_custom_providers.append({
                    "provide_token": cp.provide_token,
                    "file": str(file_path),
                    "line": cp.line_number,
                    "strategy": cp.strategy or "",
                    "strategy_target": cp.strategy_target or "",
                    "inject_deps": cp.inject_deps[:10],
                })

            # ── Config Modules ───────────────────────────────────────
            for cm in result.config_modules:
                matrix.nestjs_enhanced_config_modules.append({
                    "file": str(file_path),
                    "line": cm.line_number,
                    "is_global": cm.is_global,
                    "has_validation": cm.has_validation,
                    "config_factories": cm.config_factories[:10],
                    "expand_variables": cm.expand_variables,
                })

            # ── Env Vars ─────────────────────────────────────────────
            for ev in result.env_vars:
                matrix.nestjs_enhanced_env_vars.append({
                    "name": ev.name,
                    "file": str(file_path),
                    "line": ev.line_number,
                    "source": ev.source or "",
                    "default_value": ev.default_value or "",
                    "type_hint": ev.type_hint or "",
                    "is_required": ev.is_required,
                })

            # ── Config Usages ────────────────────────────────────────
            for cu in result.config_usages:
                matrix.nestjs_enhanced_config_usages.append({
                    "key": cu.key,
                    "file": str(file_path),
                    "line": cu.line_number,
                    "method": cu.method or "get",
                    "type_param": cu.type_param or "",
                    "has_default": cu.has_default,
                    "namespace": cu.namespace or "",
                })

            # ── Swagger Decorators ───────────────────────────────────
            for sw in result.swagger_decorators:
                matrix.nestjs_enhanced_swagger_decorators.append({
                    "decorator": sw.decorator,
                    "value": sw.value or "",
                    "file": str(file_path),
                    "line": sw.line_number,
                    "target": sw.target or "",
                    "status_code": sw.status_code,
                    "description": sw.description or "",
                })

            # ── API Properties ───────────────────────────────────────
            for ap in result.api_properties:
                matrix.nestjs_enhanced_api_properties.append({
                    "name": ap.name,
                    "file": str(file_path),
                    "line": ap.line_number,
                    "dto_class": ap.dto_class or "",
                    "property_type": ap.property_type or "",
                    "is_optional": ap.is_optional,
                    "is_array": ap.is_array,
                    "has_validation": ap.has_validation,
                })

            # ── DTOs ─────────────────────────────────────────────────
            for dto in result.dtos:
                matrix.nestjs_enhanced_dtos.append({
                    "class_name": dto.class_name,
                    "file": str(file_path),
                    "line": dto.line_number,
                    "extends": dto.extends or "",
                    "has_swagger": dto.has_swagger,
                    "has_validation": dto.has_validation,
                    "total_properties": dto.total_properties,
                })

        except Exception as e:
            import logging
            logging.getLogger('codetrellis').debug(f"NestJS enhanced parse failed for {file_path}: {e}")

    def _parse_fastify(self, file_path: Path, matrix: ProjectMatrix):
        """
        Parse Fastify file using EnhancedFastifyParser.
        v4.82: Fastify backend framework support. Runs on JS/TS files where
        Fastify is detected. Extracts routes, plugins, hooks, schemas,
        type providers, decorators, resources, and serializers.
        Supports Fastify 3.x through 5.x.
        """
        try:
            content = file_path.read_text()
            if not content.strip():
                return

            # Only parse if file contains Fastify code
            if not self.fastify_parser.is_fastify_file(content, str(file_path)):
                return

            result = self.fastify_parser.parse(content, str(file_path))

            # ── Metadata ────────────────────────────────────────────
            for fw in result.detected_frameworks:
                if fw not in matrix.fastify_detected_frameworks:
                    matrix.fastify_detected_frameworks.append(fw)

            if result.fastify_version and (
                not matrix.fastify_version or result.fastify_version > matrix.fastify_version
            ):
                matrix.fastify_version = result.fastify_version

            if result.is_typescript:
                matrix.fastify_is_typescript = True

            # ── Routes ──────────────────────────────────────────────
            for route in result.routes:
                matrix.fastify_routes.append({
                    "method": route.method,
                    "path": route.path,
                    "handler": route.handler or "anonymous",
                    "file": str(file_path),
                    "line": route.line_number,
                    "is_async": route.is_async,
                    "has_schema": route.has_schema,
                    "has_prehandler": route.has_prehandler,
                    "has_params": route.has_params,
                    "param_names": route.param_names[:10],
                    "constraint": route.constraint or "",
                })

            # ── Route Options ───────────────────────────────────────
            for ro in result.route_options:
                matrix.fastify_route_options.append({
                    "method": ro.method or "",
                    "path": ro.path or "",
                    "file": str(file_path),
                    "line": ro.line_number,
                    "has_schema": ro.has_schema,
                    "has_handler": ro.has_handler,
                    "has_prehandler": ro.has_prehandler,
                    "has_on_request": ro.has_on_request,
                })

            # ── Plugins ─────────────────────────────────────────────
            for plugin in result.plugins:
                matrix.fastify_plugins.append({
                    "name": plugin.name,
                    "file": str(file_path),
                    "line": plugin.line_number,
                    "is_async": plugin.is_async,
                    "uses_fp": plugin.uses_fp,
                    "encapsulation": plugin.encapsulation or "encapsulated",
                })

            # ── Registrations ───────────────────────────────────────
            for reg in result.registrations:
                matrix.fastify_registrations.append({
                    "plugin_name": reg.plugin_name,
                    "file": str(file_path),
                    "line": reg.line_number,
                    "prefix": reg.prefix or "",
                    "is_autoload": reg.is_autoload,
                    "source_package": reg.source_package or "",
                })

            # ── Decorators ──────────────────────────────────────────
            for dec in result.decorators:
                matrix.fastify_decorators.append({
                    "name": dec.name,
                    "file": str(file_path),
                    "line": dec.line_number,
                    "target": dec.target or "",
                    "value_type": dec.value_type or "",
                })

            # ── Hooks ───────────────────────────────────────────────
            for hook in result.hooks:
                matrix.fastify_hooks.append({
                    "hook_name": hook.hook_name,
                    "file": str(file_path),
                    "line": hook.line_number,
                    "hook_category": hook.hook_category or "",
                    "is_async": hook.is_async,
                    "handler_name": hook.handler_name or "",
                    "is_route_level": hook.is_route_level,
                })

            # ── Schemas ─────────────────────────────────────────────
            for schema in result.schemas:
                matrix.fastify_schemas.append({
                    "schema_id": schema.schema_id or "",
                    "file": str(file_path),
                    "line": schema.line_number,
                    "schema_type": schema.schema_type or "",
                    "target": schema.target or "",
                    "has_required": schema.has_required,
                    "property_count": schema.property_count,
                    "uses_ref": schema.uses_ref,
                    "ref_ids": schema.ref_ids[:10],
                })

            # ── Type Providers ──────────────────────────────────────
            for tp in result.type_providers:
                matrix.fastify_type_providers.append({
                    "provider": tp.provider or "",
                    "file": str(file_path),
                    "line": tp.line_number,
                })

            # ── Resources ───────────────────────────────────────────
            for res in result.resources:
                matrix.fastify_resources.append({
                    "name": res.name,
                    "base_path": res.base_path or "",
                    "file": str(file_path),
                    "operations": res.operations[:10],
                    "has_list": res.has_list,
                    "has_detail": res.has_detail,
                    "has_create": res.has_create,
                    "has_update": res.has_update,
                    "has_delete": res.has_delete,
                })

            # ── Serializers ─────────────────────────────────────────
            for ser in result.serializers:
                matrix.fastify_serializers.append({
                    "file": str(file_path),
                    "line": ser.line_number,
                    "serializer_type": ser.serializer_type or "",
                    "content_type": ser.content_type or "",
                })

        except Exception as e:
            import logging
            logging.getLogger('codetrellis').debug(f"Fastify parse failed for {file_path}: {e}")

    def _parse_koa(self, file_path: Path, matrix: ProjectMatrix):
        """
        Parse Koa file using EnhancedKoaParser.
        v4.83: Koa backend framework support. Runs on JS/TS files where
        Koa is detected. Extracts routes, routers, middleware, context usage,
        error throws, configuration, API patterns, and resources.
        Supports Koa 1.x through 2.x.
        """
        try:
            content = file_path.read_text()
            if not content.strip():
                return

            # Only parse if file contains Koa code
            if not self.koa_parser.is_koa_file(content, str(file_path)):
                return

            result = self.koa_parser.parse(content, str(file_path))

            # ── Metadata ────────────────────────────────────────────
            for fw in result.detected_frameworks:
                if fw not in matrix.koa_detected_frameworks:
                    matrix.koa_detected_frameworks.append(fw)

            if result.koa_version and (
                not matrix.koa_version or result.koa_version > matrix.koa_version
            ):
                matrix.koa_version = result.koa_version

            if result.is_typescript:
                matrix.koa_is_typescript = True

            if result.uses_generator_middleware:
                matrix.koa_uses_generator_middleware = True

            # ── Routes ──────────────────────────────────────────────
            for route in result.routes:
                matrix.koa_routes.append({
                    "method": route.method,
                    "path": route.path,
                    "handler": route.handler or "",
                    "file": str(file_path),
                    "line": route.line_number,
                    "is_async": route.is_async,
                    "middleware": route.middleware_names[:10],
                    "params": route.param_names[:10],
                    "route_name": route.route_name or "",
                })

            # ── Routers ─────────────────────────────────────────────
            for router in result.routers:
                matrix.koa_routers.append({
                    "name": router.name,
                    "file": str(file_path),
                    "line": router.line_number,
                    "prefix": router.prefix or "",
                    "route_count": router.route_count,
                    "router_package": router.router_package or "",
                })

            # ── Params ──────────────────────────────────────────────
            for param in result.params:
                matrix.koa_params.append({
                    "name": param.param_name,
                    "handler": param.handler or "",
                    "file": str(file_path),
                })

            # ── Middleware ───────────────────────────────────────────
            for mw in result.middleware:
                matrix.koa_middleware.append({
                    "name": mw.name,
                    "file": str(file_path),
                    "line": mw.line_number,
                    "middleware_type": mw.middleware_type or "",
                    "category": mw.category or "",
                    "is_global": mw.is_global,
                    "mount_path": mw.mount_path or "",
                    "source_package": mw.source_package or "",
                })

            # ── Middleware Stack ─────────────────────────────────────
            if result.middleware_stack:
                ms = result.middleware_stack
                matrix.koa_middleware_stacks.append({
                    "file": str(file_path),
                    "has_cors": ms.has_cors,
                    "has_helmet": ms.has_helmet,
                    "has_compression": ms.has_compression,
                    "has_session": ms.has_session,
                    "has_auth": ms.has_auth,
                    "has_rate_limiting": ms.has_rate_limiting,
                    "has_body_parser": ms.has_body_parser,
                    "has_logger": ms.has_logger,
                    "has_static": ms.has_static,
                    "has_error_handler": ms.has_error_handler,
                })

            # ── Context Usages ──────────────────────────────────────
            for ctx in result.context_usages:
                matrix.koa_context_usages.append({
                    "property_path": ctx.property_path,
                    "usage_type": ctx.usage_type or "",
                    "file": str(file_path),
                    "line": ctx.line_number,
                })

            # ── Error Throws ────────────────────────────────────────
            for et in result.error_throws:
                matrix.koa_error_throws.append({
                    "method": et.method,
                    "status_code": et.status_code or "",
                    "message": et.message or "",
                    "file": str(file_path),
                    "line": et.line_number,
                })

            # ── Custom Context ──────────────────────────────────────
            for cc in result.custom_context:
                matrix.koa_custom_context.append({
                    "property": cc.property_name,
                    "file": str(file_path),
                    "line": cc.line_number,
                })

            # ── Settings ────────────────────────────────────────────
            for setting in result.settings:
                matrix.koa_settings.append({
                    "name": setting.name,
                    "value": setting.value or "",
                    "file": str(file_path),
                    "line": setting.line_number,
                    "setting_type": setting.setting_type or "",
                    "is_env_based": setting.is_env_based,
                })

            # ── Apps ────────────────────────────────────────────────
            for app in result.apps:
                matrix.koa_apps.append({
                    "variable_name": app.variable_name,
                    "file": str(file_path),
                    "line": app.line_number,
                    "is_exported": app.is_exported,
                })

            # ── Servers ─────────────────────────────────────────────
            for srv in result.servers:
                matrix.koa_servers.append({
                    "file": str(file_path),
                    "line": srv.line_number,
                    "port": srv.port or "",
                    "is_https": srv.is_https,
                    "uses_cluster": srv.uses_cluster,
                })

            # ── Resources ───────────────────────────────────────────
            for res in result.resources:
                matrix.koa_resources.append({
                    "name": res.name,
                    "base_path": res.base_path or "",
                    "file": str(file_path),
                    "routes": res.routes,
                    "methods": res.methods[:10],
                    "has_crud": res.has_crud,
                })

        except Exception as e:
            import logging
            logging.getLogger('codetrellis').debug(f"Koa parse failed for {file_path}: {e}")

